  * the legal folder of your Openbravo installation.
  * Software distributed under the License is distributed on an
  * "AS IS" basis, WITHOUT WARRANTY OF ANY KIND, either express or
  * implied. See the License for the specific language governing rights
  * and limitations under the License.
  * The Original Code is  Compiere  ERP  Solution
  * The Initial Developer of the Original Code is Jorg Janke and ComPiere, Inc.
  * Portions created by Jorg Janke are Copyright (C) 1999-2001 Jorg Janke,
  * parts created by ComPiere are Copyright (C) ComPiere, Inc.;
  * All Rights Reserved.
  * Contributor(s): Rodney Jacome
  * Contributions are Copyright (C) 2001-2011 Openbravo, S.L.U.
  *
  * Specifically, this derivative work is based upon the following Compiere
  * file and version.

  ************************************************************************/
    -- Logistic
    v_ResultStr VARCHAR2(2000):='';
    v_Message VARCHAR2(2000):='';
    v_Record_ID VARCHAR2(32);

    -- Parameter
    -- Audit
    v_AD_Client_ID VARCHAR2(32);
    v_AD_ORG_ID VARCHAR2(32);
    v_AD_USER_ID VARCHAR2(32);
    TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    Cur_Finacc_Transaction RECORD;
    Cur_withholdings  RECORD;
    -- Parameter Variables
    v_sspch_invoice_id VARCHAR2(32);
    v_fin_financial_account_from VARCHAR2(32);
    v_start_date DATE;
    v_end_date DATE;
    v_get_uuid VARCHAR2(32);
    v_c_invoice_id VARCHAR2(32);
	v_fin_payment_id VARCHAR2(32);
    v_c_order_id VARCHAR2(32);
    v_recap VARCHAR2(30);
    v_type VARCHAR2(30);
    v_lot VARCHAR2(30);
    v_date DATE;
    v_depositamt NUMBER:=0;
    v_depositamt_resp NUMBER:=0;
    v_amount NUMBER:=0;
    v_types_of_credit_id VARCHAR2(32);
    v_cards_types_id VARCHAR2(32);
    v_banktransfer_id VARCHAR2(32);
    v_expiration_date DATE;
    v_referenceno VARCHAR2(40);
    v_processor_banck_id VARCHAR2(32);
    v_reconciled VARCHAR2(40);
    v_type_IW NUMBER:=0;
    v_typeVW NUMBER:=0;
    v_typeC NUMBER:=0;
    v_typeI NUMBER:=0;
    v_AgainProcess NUMBER:=0;
    v_type_val NUMBER:=3;
    v_paymet_date DATE;
    v_outstandingamt NUMBER:=0;
    v_NoOfFields NUMBER:=0;
    v_insert_lines NUMBER:=0;
    v_trl_count NUMBER;
    v_NextNo_F VARCHAR2(32);
    -- Copy
    Cur_Fields RECORD;
    Row_Src_Field AD_Field%ROWTYPE;
    Row_Dest_Field_Trl AD_Field_Trl%ROWTYPE;

    v_field_name NVARCHAR2(60);
    v_field_desc NVARCHAR2(255);
    v_field_help NVARCHAR2(2000);
    assigned BOOLEAN;

	v_fin_finacc_transsaction_id VARCHAR2(32);

	-- RARC
	vCheck				BOOLEAN;
	vBase			  NUMBER;
	vDepositAmount	  NUMBER;
	vPricePrecision	 NUMBER;
  BEGIN
    --  Update AD_PInstance
  BEGIN --BODY
    -- Get Parameters
    v_ResultStr:='GetEntityType';
	v_Record_ID := p_ssccr_pos_card_rec_id;

	--HEAD VAR
	SELECT pcr.fin_financial_account_from_id, pcr.start_date, pcr.end_date, pcr.ad_client_id, pcr.ad_org_id,
		pcr.createdby, cu.priceprecision
	INTO v_fin_financial_account_from, v_start_date, v_end_date, v_AD_Client_ID, v_AD_ORG_ID,
		v_AD_USER_ID, vPricePrecision
	FROM ssccr_pos_card_rec pcr
		JOIN fin_financial_account ft ON ft.fin_financial_account_id = pcr.fin_financial_account_from_id
		JOIN c_currency cu ON cu.c_currency_id = ft.c_currency_id
	WHERE pcr.ssccr_pos_card_rec_id = v_Record_ID;

	FOR Cur_Finacc_Transaction IN (
		Select    fft.em_ssccr_c_invoice_id 		as "c_invoice_id"
			, fft.em_ssccr_c_order_id 		as "c_order_id"
			, fft.em_ssccr_lot 			as "lot"
			, fft.em_ssccr_ssfi_banktransfer_id 	as "ssfi_banktransfer_id"
			, fft.em_ssccr_processor_banck_id 	as "ssccr_processor_banck_id"
			, fft.em_ssccr_types_of_credit_id 	as "ssccr_types_of_credit_id"
			, fft.em_ssccr_expiration_date 		as "ssccr_expiration_date"
			, fft.em_ssccr_cards_types_id 		as "ssccr_cards_types_id"
			, fft.em_ssccr_fin_payment_id		as "fin_payment_id"
			, fft.statementdate 			as "statementdate"
			, fft.depositamt			as "depositamt"
			, CASE
		    WHEN fft.depositamt = i.grandtotal THEN tax.impuesto
		    ELSE fft.depositamt / (
		      CASE WHEN cit.c_invoice_id IS NULL THEN
		        (SELECT ct.rate
		         FROM c_tax ct
		         WHERE ct.em_ssccr_isivacardreconprocess = 'Y')
		      ELSE ct.rate
		     END / 100::numeric + 1::numeric) * (
		      CASE WHEN cit.c_invoice_id IS NULL THEN
		        (SELECT ct.rate
		         FROM c_tax ct
		         WHERE ct.em_ssccr_isivacardreconprocess = 'Y')
		      ELSE ct.rate
		     END / 100::numeric)
	  		END AS impuesto
	  		, CASE
			    WHEN fft.depositamt = i.grandtotal THEN i.totallines
			    ELSE fft.depositamt / (
			      CASE WHEN cit.c_invoice_id IS NULL THEN
			        (SELECT ct.rate
			         FROM c_tax ct
			         WHERE ct.em_ssccr_isivacardreconprocess = 'Y')
			      ELSE ct.rate
			      END / 100::numeric + 1::numeric)
			END AS totallines
			, CASE
			    WHEN fft.depositamt = i.grandtotal THEN i.grandtotal
				    ELSE fft.depositamt
			END AS grandtotal
			, fft.em_ssccr_expiration_date		as "expiration_date"
			, fft.em_ssccr_recapno 			as "referenceno"
			, fft.em_ssccr_reconciled		as "reconciled"
			, fft.fin_finacc_transaction_id
		From fin_finacc_transaction fft 
			Left Join c_invoice i on i.c_invoice_id = fft.em_ssccr_c_invoice_id  
			Left join (Select sum(taxamt) as "impuesto",c_invoice_id from c_invoicelinetax  group by c_invoice_id) tax on tax.c_invoice_id = i.c_invoice_id
			LEFT JOIN C_InvoiceTax cit on cit.c_invoice_id = i.c_invoice_id and cit.c_tax_id in(select ct.c_tax_id	
												        	From c_tax ct
														where ct.issummary = 'N' 
														and ct.IsTaxDeductable = 'Y'	
														and ct.rate > 0 )
	  		LEFT JOIN C_Tax ct on ct.C_Tax_id = cit.C_Tax_id
		Where fin_finacc_transaction_id = p_fin_finacc_transaction_id
		AND fft.Trxtype = 'BPD'
	) LOOP
		v_c_invoice_id		:= Cur_Finacc_Transaction.c_invoice_id;
		v_c_order_id		:= Cur_Finacc_Transaction.c_order_id;
		v_lot			:= Cur_Finacc_Transaction.lot;
		v_date			:= Cur_Finacc_Transaction.statementdate;
		v_amount		:= Cur_Finacc_Transaction.depositamt;
		v_types_of_credit_id	:= Cur_Finacc_Transaction.ssccr_types_of_credit_id;
		v_expiration_date	:= Cur_Finacc_Transaction.expiration_date;
		v_cards_types_id	:= Cur_Finacc_Transaction.ssccr_cards_types_id;
		v_banktransfer_id	:= Cur_Finacc_Transaction.ssfi_banktransfer_id;
		v_referenceno		:= Cur_Finacc_Transaction.referenceno;
		v_processor_banck_id	:= Cur_Finacc_Transaction.ssccr_processor_banck_id;
		v_reconciled		:= 'Y';
		v_fin_payment_id	:= Cur_Finacc_Transaction.fin_payment_id;

		If(v_cards_types_id IS NULL OR v_types_of_credit_id IS NULL OR  v_processor_banck_id IS NULL)Then
			RAISE_APPLICATION_ERROR(-20000,'@SSCCR_Load_Config_Empty_Lines@ ');
		End If;
		v_type_IW := 0;
		v_typeVW := 0;
		v_typeC := 0;
		v_depositamt_resp:= 0;

		--RARC
		vCheck := v_c_invoice_id IS NULL OR COALESCE(Cur_Finacc_Transaction.impuesto,0) = 0;
		vBase := COALESCE(v_amount,0)/(1::numeric + (CASE WHEN v_c_invoice_id IS NULL THEN
			        								  (SELECT ct.rate FROM c_tax ct
									   					WHERE ct.em_ssccr_isivacardreconprocess = 'Y' 
									   					AND ct.issummary = 'N' 
									   					AND ct.IsTaxDeductable = 'Y'
									   					AND ct.rate > 0)
			      									ELSE (SELECT ct.rate FROM c_invoice ci
														LEFT JOIN C_InvoiceTax cit ON cit.c_invoice_id = ci.c_invoice_id AND cit.c_tax_id IN(SELECT ct.c_tax_id
																								FROM c_tax ct
																								WHERE ct.issummary = 'N' 
																								AND ct.IsTaxDeductable = 'Y'
																								AND ct.rate > 0)
														LEFT JOIN C_Tax ct ON ct.C_Tax_id = cit.C_Tax_id
														WHERE ci.c_invoice_id = v_c_invoice_id)
				  									END) / 100::numeric);

		FOR Cur_withholdings IN (
			Select sw.porcentage ,sw.type
			From ssccr_cardmatchingconf  cmc
				Join ssccr_cardmatchingconfline  cmcl on cmcl.ssccr_cardmatchingconf_id = cmc.ssccr_cardmatchingconf_id
				Join ssccr_withholdings sw on sw.ssccr_cardmatchingconfline_id = cmcl.ssccr_cardmatchingconfline_id
			Where sw.type IN ('IW' , 'VW' , 'C','IVA')
				And v_date Between cmcl.from_validity And cmcl.valid_up
				And cmcl.ssccr_cards_types_id = v_cards_types_id
				And cmcl.ssccr_types_of_credit_id = v_types_of_credit_id
				And cmcl.income_withholding = 'IW'
		)Loop
			v_type	:= Cur_withholdings.type;

			If(v_type='IW')Then--Retencion Renta
				v_amount := CASE WHEN vCheck THEN vBase ELSE Cur_Finacc_Transaction.totallines END;
				v_type_IW := v_type_IW + 1;
			End If;
			If(v_type='VW')Then--Retencion IVA
				v_amount := CASE WHEN vCheck THEN vBase*((CASE WHEN v_c_invoice_id IS NULL THEN
			        									  (SELECT ct.rate FROM c_tax ct
									   						WHERE ct.em_ssccr_isivacardreconprocess = 'Y' 
									   						AND ct.issummary = 'N' 
									   						AND ct.IsTaxDeductable = 'Y'
									   						AND ct.rate > 0)
			      										ELSE (SELECT ct.rate FROM c_invoice ci
															LEFT JOIN C_InvoiceTax cit ON cit.c_invoice_id = ci.c_invoice_id AND cit.c_tax_id IN(SELECT ct.c_tax_id
																									FROM c_tax ct
																									WHERE ct.issummary = 'N' 
																									AND ct.IsTaxDeductable = 'Y'
																									AND ct.rate > 0)
															LEFT JOIN C_Tax ct ON ct.C_Tax_id = cit.C_Tax_id
															WHERE ci.c_invoice_id = v_c_invoice_id)
				  										END) / 100::numeric)  ELSE Cur_Finacc_Transaction.impuesto END;
				v_typeVW := v_typeVW + 1;
			End If;
			If(v_type='C')Then--Comision
				v_amount := Cur_Finacc_Transaction.grandtotal;
				v_typeC := v_typeC + 1;
			End If;
			If(v_type='IVA')Then--IVA
				v_amount := Cur_Finacc_Transaction.grandtotal;
				v_typeI := v_typeI + 1;
			End If;
			v_depositamt 	:=	v_amount * Cur_withholdings.porcentage / 100;
			v_get_uuid 	:= 	get_uuid();

			Select COUNT(*)
				INTO v_AgainProcess
			From ssccr_pos_card_rec_line 
			Where fin_payment_id = v_fin_payment_id
				And type = v_type;

			v_AgainProcess:=0;

			If (v_AgainProcess = 0) Then
				SELECT deposit_amount INTO vDepositAmount
				FROM ssccr_card_rec_summary_v
				WHERE fin_finacc_transaction_id = Cur_Finacc_Transaction.fin_finacc_transaction_id
					AND type = v_type;
				vDepositAmount := COALESCE(vDepositAmount, 0.0);

				IF ROUND(v_depositamt - vDepositAmount, 2) > 0 THEN
					INSERT INTO ssccr_pos_card_rec_line(
						ssccr_pos_card_rec_line_id, ad_client_id, ad_org_id, createdby, updatedby,
						c_invoice_id, c_order_id, recap, lot, date_statement,
						amount, deposit_amount, type, reconciled, ssccr_types_of_credit_id,
						expiration_date, ssccr_cards_types_id, ssccr_processor_banck_id, ssccr_pos_card_rec_id, ssfi_banktransfer_id,
						fin_payment_id, group_id, deposit_amount_original
					) VALUES (
						v_get_uuid, v_AD_Client_ID, v_AD_ORG_ID, v_AD_USER_ID, v_AD_USER_ID,
						v_c_invoice_id, v_c_order_id, v_referenceno, v_lot, v_date,
						ROUND(v_amount, vPricePrecision), ROUND(v_depositamt - vDepositAmount, vPricePrecision), v_type, v_reconciled, v_types_of_credit_id,
						v_expiration_date, v_cards_types_id	, v_processor_banck_id, v_Record_ID, v_banktransfer_id,
						v_fin_payment_id, Cur_Finacc_Transaction.fin_finacc_transaction_id, ROUND(v_depositamt - vDepositAmount, vPricePrecision)
					);
					v_insert_lines		:= v_insert_lines + 1;
				END IF;
			End IF;
			v_depositamt_resp	:= v_depositamt_resp + v_depositamt;

		End Loop; --END Cur_withholdings
		v_type_val := 4;
		v_type_val := v_type_val - v_type_IW - v_typeVW - v_typeC - v_typeI;

		IF(v_type_val <> 0)Then
			If(v_type_val<0)Then
				RAISE EXCEPTION '%','@SSCCR_Load_Too_Many_Lines@ '||(select name From ssccr_processor_banck where ssccr_processor_banck_id = v_processor_banck_id)
				||', '||(Select name from ssccr_cards_types  where ssccr_cards_types_id  = v_cards_types_id)
				||', '||(Select name From ssccr_types_of_credit  where ssccr_types_of_credit_id = v_types_of_credit_id); --OBTG:-20000--
			Else
				RAISE EXCEPTION '%','@SSCCR_Load_dont_find_Lines@ ' ||(select name From ssccr_processor_banck where ssccr_processor_banck_id = v_processor_banck_id)
				||', '||(Select name from ssccr_cards_types  where ssccr_cards_types_id  = v_cards_types_id)
				||', '||(Select name From ssccr_types_of_credit  where ssccr_types_of_credit_id = v_types_of_credit_id); --OBTG:-20000--
			End IF;
		End if;

		v_type			:= 'B';
		v_amount		:= ROUND(Cur_Finacc_Transaction.depositamt, vPricePrecision);	
		v_depositamt	:= ROUND(v_amount - v_depositamt_resp, vPricePrecision);
		v_get_uuid 		:= get_uuid();

		Select COUNT(*)
			INTO v_AgainProcess
		From ssccr_pos_card_rec_line 
		Where fin_payment_id = v_fin_payment_id 
			And type = v_type;

		v_AgainProcess:=0;

		If (v_AgainProcess = 0) Then

			if(v_type='B')then
				v_fin_finacc_transsaction_id:=Cur_Finacc_Transaction.fin_finacc_transaction_id;
			else
				v_fin_finacc_transsaction_id:=null;
			end if;

			SELECT deposit_amount INTO vDepositAmount
			FROM ssccr_card_rec_summary_v
			WHERE fin_finacc_transaction_id = Cur_Finacc_Transaction.fin_finacc_transaction_id
				AND type = v_type;
			vDepositAmount := COALESCE(vDepositAmount, 0.0);

			v_depositamt := v_depositamt - vDepositAmount;

			IF ROUND(v_depositamt, 2) > 0 THEN
				INSERT INTO ssccr_pos_card_rec_line(
					ssccr_pos_card_rec_line_id, ad_client_id, ad_org_id, createdby, updatedby,
					c_invoice_id, c_order_id, recap, lot, date_statement,
					amount, deposit_amount, type, reconciled, ssccr_types_of_credit_id,
					expiration_date, ssccr_cards_types_id, ssccr_processor_banck_id, ssccr_pos_card_rec_id, ssfi_banktransfer_id,
					fin_payment_id, fin_finacc_transsaction_id, group_id, deposit_amount_original
				) VALUES (
					v_get_uuid, v_AD_Client_ID, v_AD_ORG_ID, v_AD_USER_ID, v_AD_USER_ID,
					v_c_invoice_id, v_c_order_id, v_referenceno, v_lot, v_date,
					v_amount, v_depositamt, v_type, v_reconciled, v_types_of_credit_id,
					v_expiration_date, v_cards_types_id, v_processor_banck_id, v_Record_ID, v_banktransfer_id,
					v_fin_payment_id, v_fin_finacc_transsaction_id, v_fin_finacc_transsaction_id, v_depositamt
				);
				v_insert_lines		:= v_insert_lines + 1;
			END IF;
		End IF;

	END LOOP; -- End Parameter

    v_Message:='@RowsInserted@=' || v_insert_lines ;
    --<<FINISH_PROCESS>>

    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message) ;
   RETURN 'OK';
END; --BODY
EXCEPTION
WHEN OTHERS THEN
  v_ResultStr:= '@ERROR=' || SQLERRM;
  RETURN v_ResultStr;
END SSCCR_LOAD_LINES_ONE
